edits.newText:
function clearPlanPanel(pi: { setHeader: (f: any) => void }): void {
	stopPlanTimer();
	planState = null;
	planContainer = null;
	planTUI = null;
	lastActivityFeedText = "";
	pi.setHeader(undefined);
}

function setupPlanPanel(goal: string, stepLabels: string[], pi: { setHeader: (f: any) => void }): void {
	planState = {
		goal,
		steps: stepLabels.map((label, i) => ({
			label,
			completed: false,
			active: i === 0,
		})),
		startTime: Date.now(),
	};
	pi.setHeader((tui: TUI, theme: any) => buildPlanPanel(tui, theme));
	startPlanTimer();
	updatePlanDisplay();
}

function completePlanStep(pi: { setHeader: (f: any) => void }): void {
	if (!planState) return;
	const idx = planState.steps.findIndex((s) => s.active);
	if (idx >= 0) {
		planState.steps[idx].completed = true;
		planState.steps[idx].active = false;
	}
	const next = idx + 1;
	if (next < planState.steps.length) {
		planState.steps[next].active = true;
	}
	updatePlanDisplay();
}

