	// If no steps yet, show starting
	if (state.steps.length === 0) {
		lines.push(`  в Ӣ Starting...`);
		return lines.join("\n");
	}

	const total = state.steps.length;
	const completed = state.steps.filter((s) => s.completed).length;

	// Task box with goal
	if (state.goal) {
		const boxWidth = Math.max(state.goal.length + 4, 30);
		const padding = boxWidth - 4;
		const truncated = state.goal.length > padding ? state.goal.slice(0, padding - 3) + "..." : state.goal;
		const pad = padding - truncated.length;
		lines.push(`в”Ңв”Җ Task ${("в”Җ").repeat(Math.max(0, boxWidth - 7))}в”җ`);
		lines.push(`в”Ӯ ${truncated}${(" ").repeat(pad)} в”Ӯ`);
		lines.push(`в””${("в”Җ").repeat(Math.max(0, boxWidth - 2))}в”ҳ`);
	}

	// Progress dots
	const dots = state.steps.map((s, i) => {
		if (s.completed) return "в—Ҹ";
		if (i === state.currentStep) return "в—Ҹ";
		return "в—Ӣ";
